.PHONY: help init plan apply destroy kubeconfig argocd-password bootstrap-cluster

ENV       ?= ontwikkel
STATE_DIR := $(HOME)/.tofu/state/platform-$(ENV)
SECRETS   := envs/$(ENV)/secrets.sops.yaml
TFVARS    := envs/$(ENV)/terraform.tfvars

help:
	@echo "InfraWeaver Platform — Talos + ArgoCD on Proxmox"
	@echo ""
	@echo "Usage:  make <target> ENV=<ontwikkel|productie>"
	@echo ""
	@echo "Deployment workflow:"
	@echo "  1. make init         Initialize OpenTofu for the target environment"
	@echo "  2. make cluster      Deploy Talos cluster (stage 1)"
	@echo "  3. make platform     Deploy ArgoCD + ApplicationSet (stage 2)"
	@echo "  4. make kubeconfig   Export kubeconfig to ~/.kube/"
	@echo ""
	@echo "Shortcuts:"
	@echo "  make plan            Plan infrastructure changes (full)"
	@echo "  make apply           Apply all changes (full)"
	@echo "  make destroy         Destroy all platform infrastructure"
	@echo ""
	@echo "Operations:"
	@echo "  make kubeconfig      Export kubeconfig to ~/.kube/config-platform-<env>"
	@echo "  make talosconfig     Export talosconfig to ~/.talos/config-platform-<env>"
	@echo "  make argocd-pass     Get ArgoCD initial admin password"
	@echo "  make nodes           Show cluster nodes (kubectl)"
	@echo "  make argocd-ui       Port-forward ArgoCD UI to localhost:8080"
	@echo ""
	@echo "Secrets (SOPS/age):"
	@echo "  export SOPS_AGE_KEY_FILE=~/.config/sops/age/keys.txt"
	@echo "  sops --encrypt --in-place $(SECRETS)"

# ---------------------------------------------------------------------------
# Internal helpers
# ---------------------------------------------------------------------------

# Run a tofu command with secrets decrypted from SOPS into the environment.
# Falls back to env vars already set if secrets.sops.yaml is absent.
define tofu-with-secrets
	@if [ -f "$(SECRETS)" ] && which sops >/dev/null 2>&1; then \
		echo "==> Decrypting secrets from $(SECRETS)..."; \
		sops exec-env "$(SECRETS)" \
			"cd terraform && tofu $(1) -var-file='../$(TFVARS)'"; \
	else \
		echo "WARN: SOPS secrets not found or sops not installed. Using env vars."; \
		cd terraform && tofu $(1) -var-file='../$(TFVARS)'; \
	fi
endef

# ---------------------------------------------------------------------------
# Core targets
# ---------------------------------------------------------------------------

init:
	mkdir -p $(STATE_DIR)
	cd terraform && tofu init \
		-backend-config="path=$(STATE_DIR)/terraform.tfstate" \
		-reconfigure

# Stage 1: Deploy Talos cluster only (writes kubeconfig to envs/ENV/generated/)
cluster: init
	$(call tofu-with-secrets,apply -target=module.talos_cluster -target=local_sensitive_file.kubeconfig -target=local_sensitive_file.talosconfig -auto-approve)

# Stage 2: Deploy ArgoCD + ApplicationSet (requires cluster to be running)
platform: init
	$(call tofu-with-secrets,apply -var='deploy_platform_bootstrap=true' -auto-approve)

plan: init
	$(call tofu-with-secrets,plan -out=tfplan)

apply: init
	$(call tofu-with-secrets,apply -auto-approve)

destroy: init
	$(call tofu-with-secrets,destroy -auto-approve)

# ---------------------------------------------------------------------------
# Operations
# ---------------------------------------------------------------------------

kubeconfig:
	mkdir -p ~/.kube
	./scripts/get-kubeconfig.sh $(ENV) ~/.kube/config-platform-$(ENV)
	@echo "✅ Kubeconfig: ~/.kube/config-platform-$(ENV)"
	@echo "   export KUBECONFIG=~/.kube/config-platform-$(ENV)"

talosconfig:
	mkdir -p ~/.talos
	@if [ -f "envs/$(ENV)/generated/talosconfig" ]; then \
		cp envs/$(ENV)/generated/talosconfig ~/.talos/config-platform-$(ENV); \
		chmod 600 ~/.talos/config-platform-$(ENV); \
		echo "✅ Talosconfig: ~/.talos/config-platform-$(ENV)"; \
		echo "   export TALOSCONFIG=~/.talos/config-platform-$(ENV)"; \
	else \
		echo "ERROR: envs/$(ENV)/generated/talosconfig not found."; \
		echo "       Run 'make cluster ENV=$(ENV)' first."; \
		exit 1; \
	fi

argocd-pass:
	KUBECONFIG=~/.kube/config-platform-$(ENV) \
		kubectl -n argocd get secret argocd-initial-admin-secret \
		-o jsonpath="{.data.password}"

# =============================================================================
# Root module — outputs.tf
# =============================================================================

output "cluster_endpoint" {
  description = "Kubernetes API server endpoint URL."
  value       = module.talos_cluster.cluster_endpoint
}

output "node_ips" {
  description = "Map of Talos node names to their IP addresses."
  value       = module.talos_cluster.node_ips
}

output "controlplane_ips" {
  description = "List of control-plane node IP addresses."
  value       = module.talos_cluster.controlplane_ips
}

output "kubeconfig_path" {
  description = "Local path to the generated kubeconfig file."
  value       = "${path.root}/../envs/${var.environment}/generated/kubeconfig"
}

output "talosconfig_path" {
  description = "Local path to the generated talosconfig file."
  value       = "${path.root}/../envs/${var.environment}/generated/talosconfig"
}

output "kubeconfig" {
  description = "Raw kubeconfig YAML (admin credentials — handle with care)."
  value       = module.talos_cluster.kubeconfig
  sensitive   = true
}

output "talosconfig" {
  description = "Raw talosconfig YAML for talosctl."
  value       = module.talos_cluster.talosconfig
  sensitive   = true
}

output "argocd_namespace" {
  description = "Namespace where ArgoCD is deployed (if platform_bootstrap is enabled)."
  value       = var.deploy_platform_bootstrap ? module.platform_bootstrap[0].argocd_namespace : null
}

# =============================================================================
# Root module — providers.tf
# =============================================================================

terraform {
  required_version = ">= 1.6.0"

  required_providers {
    proxmox = {
      source  = "bpg/proxmox"
      version = "~> 0.78"
    }
    talos = {
      source  = "siderolabs/talos"
      version = "~> 0.7"
    }
    helm = {
      source  = "hashicorp/helm"
      version = "~> 2.0"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.0"
    }
    null = {
      source  = "hashicorp/null"
      version = "~> 3.0"
    }
    local = {
      source  = "hashicorp/local"
      version = "~> 2.0"
    }
    time = {
      source  = "hashicorp/time"
      version = "~> 0.9"
    }
  }
}

# ---------------------------------------------------------------------------
# Proxmox provider
#
# Connects to the Proxmox cluster management API at proxmox_host:8006.
# SSH is configured with the deployer key; the provider resolves per-node SSH
# connections via the Proxmox API for operations that require node-level SSH.
# ---------------------------------------------------------------------------

locals {
  cluster_config               = yamldecode(file("${path.root}/../envs/${var.environment}/cluster.yaml"))
  proxmox_host                 = local.cluster_config.proxmox_host
  proxmox_ssh_private_key_file = pathexpand("~/.ssh/deployer_ed25519")

  # Generated kubeconfig path — written by local_sensitive_file.kubeconfig
  kubeconfig_path = "${path.root}/../envs/${var.environment}/generated/kubeconfig"
}

provider "proxmox" {
  endpoint  = "https://${local.proxmox_host}:8006/"
  api_token = var.proxmox_api_token
  insecure  = true # Proxmox commonly uses self-signed certs in homelab

  ssh {
    agent       = false
    username    = "root"
    private_key = file(local.proxmox_ssh_private_key_file)
  }
}

# ---------------------------------------------------------------------------
# Talos provider — no configuration needed; all parameters are passed per-resource
# ---------------------------------------------------------------------------

provider "talos" {}

# ---------------------------------------------------------------------------
# Kubernetes provider
#
# Reads the kubeconfig written by the talos-cluster module into
# envs/ENV/generated/kubeconfig.
#
# IMPORTANT: On first apply, run with -target=module.talos_cluster first so
# this file is created before the kubernetes/helm providers are used:
#
#   tofu apply -target=module.talos_cluster
#   tofu apply
# ---------------------------------------------------------------------------

provider "kubernetes" {
  config_path = local.kubeconfig_path
}

# ---------------------------------------------------------------------------
# Helm provider — same kubeconfig as kubernetes provider
# ---------------------------------------------------------------------------

provider "helm" {
  kubernetes {
    config_path = local.kubeconfig_path
  }
}

# ---------------------------------------------------------------------------
# Null, local, time providers — no configuration required
# ---------------------------------------------------------------------------

provider "null" {}
provider "local" {}
provider "time" {}

# =============================================================================
# Root module — variables.tf
# =============================================================================

# ---------------------------------------------------------------------------
# Secrets (values come from SOPS-decrypted envs/ENV/secrets.sops.yaml)
# ---------------------------------------------------------------------------

variable "proxmox_api_token" {
  description = <<-EOT
    Proxmox API token in format: <user>@<realm>!<token>=<uuid>.
    Example: terraform@pve!platform=xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx
    Supply via TF_VAR_proxmox_api_token or secrets.sops.yaml.
  EOT
  type        = string
  sensitive   = true

  validation {
    condition     = can(regex("^.+@.+!.+=.+$", var.proxmox_api_token))
    error_message = "proxmox_api_token must be in format: <user>@<realm>!<token>=<uuid>."
  }
}

variable "openbao_token" {
  description = "OpenBao (Vault) root or platform service token. Supply via secrets.sops.yaml."
  type        = string
  sensitive   = true
  default     = ""
}

variable "openbao_address" {
  description = "OpenBao API address (e.g. https://10.25.0.241:8200). Read from cluster.yaml."
  type        = string
  default     = ""

  validation {
    condition     = var.openbao_address == "" || can(regex("^https?://", var.openbao_address))
    error_message = "openbao_address must be a valid HTTP(S) URL or empty string."
  }
}

variable "github_runner_token" {
  description = "GitHub Actions runner registration token. Supply via secrets.sops.yaml."
  type        = string
  sensitive   = true
  default     = ""
}

# ---------------------------------------------------------------------------
# Cluster identity (non-sensitive; may be set in terraform.tfvars)
# ---------------------------------------------------------------------------

variable "cluster_name" {
  description = "Kubernetes cluster name. Must match cluster.yaml cluster_name."
  type        = string

  validation {
    condition     = can(regex("^[a-z0-9][a-z0-9-]{1,61}[a-z0-9]$", var.cluster_name))
    error_message = "cluster_name must be a lowercase DNS label (2–63 chars, [a-z0-9-])."
  }
}

variable "environment" {
  description = "Deployment environment. Controls HA mode and state backend path."
  type        = string

  validation {
    condition     = contains(["ontwikkel", "productie"], var.environment)
    error_message = "environment must be 'ontwikkel' or 'productie'."
  }
}

# ---------------------------------------------------------------------------
# Platform Git repository (used by ArgoCD ApplicationSet)
# ---------------------------------------------------------------------------

variable "git_repo_url" {
  description = "Git repository URL for the platform kubernetes manifests."
  type        = string
  default     = "https://github.com/Werewolf-p/InfraWeaver-platform"
}

variable "git_revision" {
  description = "Git branch/tag/commit ArgoCD tracks for platform manifests."
  type        = string
  default     = "HEAD"
}

# ---------------------------------------------------------------------------
# Feature flags
# ---------------------------------------------------------------------------

variable "deploy_platform_bootstrap" {
  description = <<-EOT
    Set to true to deploy the platform-bootstrap module (ArgoCD + ApplicationSet).
    On first apply, set to false (or use -target) until the cluster is ready and
    the kubeconfig has been written to envs/ENV/generated/kubeconfig.
  EOT
  type        = bool
  default     = true
}

terraform {
  # Local backend — state path is configured at init time via -backend-config.
  # See envs/ENV/backend.hcl for per-environment state path configuration.
  #
  # Init command:
  #   cd terraform
  #   tofu init -backend-config="../envs/ontwikkel/backend.hcl"   # dev
  #   tofu init -backend-config="../envs/productie/backend.hcl"   # prod
  backend "local" {}
}

# =============================================================================
# platform-bootstrap module — outputs.tf
# =============================================================================

output "argocd_namespace" {
  description = "Namespace where ArgoCD was installed."
  value       = kubernetes_namespace.argocd.metadata[0].name
}

output "argocd_server_service" {
  description = "ArgoCD server service name for port-forwarding."
  value       = "argocd-server"
}

output "app_project_name" {
  description = "ArgoCD AppProject name created for this cluster."
  value       = kubernetes_manifest.app_project.manifest.metadata.name
}

output "applicationset_name" {
  description = "ArgoCD ApplicationSet name that drives platform app deployments."
  value       = kubernetes_manifest.platform_applicationset.manifest.metadata.name
}

# =============================================================================
# platform-bootstrap module — variables.tf
# =============================================================================

variable "cluster_name" {
  description = "Kubernetes cluster name — used as the ArgoCD AppProject name."
  type        = string
}

variable "environment" {
  description = "Deployment environment (ontwikkel | productie)."
  type        = string

  validation {
    condition     = contains(["ontwikkel", "productie"], var.environment)
    error_message = "environment must be 'ontwikkel' or 'productie'."
  }
}

variable "ha_mode" {
  description = <<-EOT
    Enable HA mode for ArgoCD (replicas=2 for server and applicationSet).
    Set to true for productie, false for ontwikkel.
  EOT
  type        = bool
  default     = false
}

variable "argocd_chart_version" {
  description = "ArgoCD Helm chart version (argo/argo-cd). Pinned for reproducibility."
  type        = string
  default     = "7.8.23"

  validation {
    condition     = can(regex("^\\d+\\.\\d+\\.\\d+", var.argocd_chart_version))
    error_message = "argocd_chart_version must be a valid semver string."
  }
}

variable "git_repo_url" {
  description = <<-EOT
    Git repository URL containing the platform's Kubernetes manifests.
    ArgoCD's ApplicationSet git generator scans the `kubernetes/` directory
    of this repo and creates an Application per subdirectory.
  EOT
  type        = string
  default     = "https://github.com/Werewolf-p/InfraWeaver-platform"

  validation {
    condition     = can(regex("^https?://|^git@", var.git_repo_url))
    error_message = "git_repo_url must be a valid HTTP(S) or SSH Git URL."
  }
}

variable "git_revision" {
  description = "Git branch, tag, or commit SHA that ArgoCD tracks."
  type        = string
  default     = "HEAD"
}

variable "argocd_namespace" {
  description = "Kubernetes namespace where ArgoCD is installed."
  type        = string
  default     = "argocd"
}

variable "kubernetes_apps_path" {
  description = "Path inside the git repo where per-application directories live."
  type        = string
  default     = "kubernetes"
}

# =============================================================================
# platform-bootstrap/main.tf
#
# Bootstraps the platform layer on top of a fresh Talos cluster:
#   1. Create the argocd namespace
#   2. Install ArgoCD via Helm (argo/argo-cd chart ~7.x)
#      - HA replicas for productie, single instance for ontwikkel
#   3. Wait briefly for ArgoCD CRDs to be registered in the API server
#   4. Create an ArgoCD AppProject scoped to this cluster
#   5. Create a platform-wide ApplicationSet using a Git directory generator
#      that points to the kubernetes/ directory of the platform repo
#
# Provider dependency: kubernetes and helm providers must be configured in the
# root module and passed to this module via the `providers` argument.
# =============================================================================

terraform {
  required_providers {
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.0"
    }
    helm = {
      source  = "hashicorp/helm"
      version = "~> 2.0"
    }
    time = {
      source  = "hashicorp/time"
      version = "~> 0.9"
    }
  }
}

# ---------------------------------------------------------------------------
# ArgoCD namespace
# ---------------------------------------------------------------------------

resource "kubernetes_namespace" "argocd" {
  metadata {
    name = var.argocd_namespace

    labels = {
      "app.kubernetes.io/managed-by" = "opentofu"
      "app.kubernetes.io/part-of"    = "platform-bootstrap"
    }
  }
}

# ---------------------------------------------------------------------------
# ArgoCD Helm release
#
# HA mode (productie):
#   server.replicas = 2, applicationSet.replicas = 2
# Single mode (ontwikkel):
#   all replica counts = 1
# ---------------------------------------------------------------------------

locals {
  argocd_ha_values = {
    global = {
      # Ensure ArgoCD knows its own hostname for SSO callbacks etc.
      # Override in production with a real ingress hostname.
      domain = "argocd.${var.cluster_name}.local"
    }

    server = {
      replicas = var.ha_mode ? 2 : 1

      # Expose via ClusterIP; users port-forward or use an Ingress in front
      service = {
        type = "ClusterIP"
      }

      # Useful defaults for GitOps
      extraArgs = ["--insecure"]
    }

    applicationSet = {
      replicas = var.ha_mode ? 2 : 1
    }

    controller = {
      replicas = 1 # Application controller runs as StatefulSet; 1 is standard
    }

    repoServer = {
      replicas = var.ha_mode ? 2 : 1
    }

    redis = {
      # Use Redis HA (Sentinel) in productie for genuine HA
      enabled = !var.ha_mode
    }

    redis-ha = {
      enabled = var.ha_mode
    }

    configs = {
      params = {
        # Disable TLS between components inside the cluster (handled by mTLS if needed)
        "server.insecure" = "true"
      }
    }
  }
}

resource "helm_release" "argocd" {
  name       = "argocd"
  repository = "https://argoproj.github.io/argo-helm"
  chart      = "argo-cd"
  version    = var.argocd_chart_version
  namespace  = kubernetes_namespace.argocd.metadata[0].name

  # Render the values map to YAML and pass as a Helm values file
  values = [yamlencode(local.argocd_ha_values)]

  # ArgoCD installs can take several minutes on a fresh cluster
  timeout = 600

  # Wait for all ArgoCD pods to become Ready before proceeding
  wait          = true
  wait_for_jobs = true

  # On upgrades, allow replacing immutable resources (e.g. Jobs)
  replace = true

  depends_on = [kubernetes_namespace.argocd]
}

